module float_multi(
    input clk,
    input rst,
    input [31:0] a,
    input [31:0] b,
    output reg [31:0] z
);

    reg [2:0] counter;

    reg [23:0] a_mantissa, b_mantissa, z_mantissa;
    reg [9:0]  a_exponent, b_exponent, z_exponent;
    reg        a_sign, b_sign, z_sign;
    reg [49:0] product;
    reg        guard_bit, round_bit, sticky;

    reg [31:0] a_reg, b_reg;

    reg a_is_nan, b_is_nan;
    reg a_is_inf, b_is_inf;
    reg a_is_zero, b_is_zero;
    reg a_is_denorm, b_is_denorm;

    reg [47:0] product48;
    reg [24:0] mant_round;
    reg [9:0]  exp_temp;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            counter      <= 3'd0;
            z            <= 32'd0;

            a_mantissa   <= 24'd0;
            b_mantissa   <= 24'd0;
            z_mantissa   <= 24'd0;
            a_exponent   <= 10'd0;
            b_exponent   <= 10'd0;
            z_exponent   <= 10'd0;
            a_sign       <= 1'b0;
            b_sign       <= 1'b0;
            z_sign       <= 1'b0;
            product      <= 50'd0;
            guard_bit    <= 1'b0;
            round_bit    <= 1'b0;
            sticky       <= 1'b0;

            a_reg        <= 32'd0;
            b_reg        <= 32'd0;

            a_is_nan     <= 1'b0;
            b_is_nan     <= 1'b0;
            a_is_inf     <= 1'b0;
            b_is_inf     <= 1'b0;
            a_is_zero    <= 1'b0;
            b_is_zero    <= 1'b0;
            a_is_denorm  <= 1'b0;
            b_is_denorm  <= 1'b0;

            product48    <= 48'd0;
            mant_round   <= 25'd0;
            exp_temp     <= 10'd0;
        end else begin
            case (counter)
                3'd0: begin
                    a_reg    <= a;
                    b_reg    <= b;
                    counter  <= 3'd1;
                end

                3'd1: begin
                    a_sign <= a_reg[31];
                    b_sign <= b_reg[31];

                    a_is_nan    <= (&a_reg[30:23]) && (|a_reg[22:0]);
                    b_is_nan    <= (&b_reg[30:23]) && (|b_reg[22:0]);
                    a_is_inf    <= (&a_reg[30:23]) && (~|a_reg[22:0]);
                    b_is_inf    <= (&b_reg[30:23]) && (~|b_reg[22:0]);
                    a_is_zero   <= (~|a_reg[30:23]) && (~|a_reg[22:0]);
                    b_is_zero   <= (~|b_reg[30:23]) && (~|b_reg[22:0]);
                    a_is_denorm <= (~|a_reg[30:23]) && (|a_reg[22:0]);
                    b_is_denorm <= (~|b_reg[30:23]) && (|b_reg[22:0]);

                    if (a_reg[30:23] == 8'd0) begin
                        a_exponent <= 10'd1;
                        a_mantissa <= {1'b0, a_reg[22:0]};
                    end else begin
                        a_exponent <= {2'b00, a_reg[30:23]};
                        a_mantissa <= {1'b1, a_reg[22:0]};
                    end

                    if (b_reg[30:23] == 8'd0) begin
                        b_exponent <= 10'd1;
                        b_mantissa <= {1'b0, b_reg[22:0]};
                    end else begin
                        b_exponent <= {2'b00, b_reg[30:23]};
                        b_mantissa <= {1'b1, b_reg[22:0]};
                    end

                    z_sign  <= a_reg[31] ^ b_reg[31];
                    counter <= 3'd2;
                end

                3'd2: begin
                    if (a_is_nan || b_is_nan) begin
                        z <= 32'h7FC00000;
                        counter <= 3'd0;
                    end else if ((a_is_inf && b_is_zero) || (b_is_inf && a_is_zero)) begin
                        z <= 32'h7FC00000;
                        counter <= 3'd0;
                    end else if (a_is_inf || b_is_inf) begin
                        z <= {z_sign, 8'hFF, 23'd0};
                        counter <= 3'd0;
                    end else if (a_is_zero || b_is_zero) begin
                        z <= {z_sign, 31'd0};
                        counter <= 3'd0;
                    end else begin
                        product    <= a_mantissa * b_mantissa;
                        z_exponent <= a_exponent + b_exponent - 10'd127;
                        counter    <= 3'd3;
                    end
                end

                3'd3: begin
                    product48 <= product[47:0];

                    if (product[47]) begin
                        z_mantissa <= product[47:24];
                        guard_bit  <= product[23];
                        round_bit  <= product[22];
                        sticky     <= |product[21:0];
                        z_exponent <= z_exponent + 10'd1;
                    end else begin
                        z_mantissa <= product[46:23];
                        guard_bit  <= product[22];
                        round_bit  <= product[21];
                        sticky     <= |product[20:0];
                    end

                    counter <= 3'd4;
                end

                3'd4: begin
                    mant_round = {1'b0, z_mantissa};

                    if (guard_bit && (round_bit || sticky || z_mantissa[0]))
                        mant_round = mant_round + 25'd1;

                    if (mant_round[24]) begin
                        z_mantissa <= mant_round[24:1];
                        exp_temp   <= z_exponent + 10'd1;
                    end else begin
                        z_mantissa <= mant_round[23:0];
                        exp_temp   <= z_exponent;
                    end

                    z_exponent <= exp_temp;
                    counter    <= 3'd5;
                end

                3'd5: begin
                    if (z_exponent >= 10'd255) begin
                        z <= {z_sign, 8'hFF, 23'd0};
                    end else if (z_exponent <= 10'd0) begin
                        z <= {z_sign, 31'd0};
                    end else begin
                        z <= {z_sign, z_exponent[7:0], z_mantissa[22:0]};
                    end
                    counter <= 3'd0;
                end

                default: begin
                    counter <= 3'd0;
                end
            endcase
        end
    end

endmodule

